--- 领取奖励
function LxQuestHandler:QuestReceiveReq(refIds)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.QuestReceiveReq)
    for k,v in ipairs(refIds) do
        proto.refIds:append(v)
    end
    SendMessage(LxProtoIds.QuestReceiveReq, proto)
end

--- 领取章节奖励
function LxQuestHandler:QuestPlotRewardReq(chapterId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.QuestPlotRewardReq)
    proto.chapter = chapterId
    SendMessage(LxProtoIds.QuestPlotRewardReq, proto)
end

