function LxQuestHandler:OnQuestListResp(pb)
    if #pb.questList > 0 then
        for i,v in ipairs(pb.questList) do
            ModuleCenter.Quest:AddQuest(v)
        end
    end
    FireEvent(EventNames.QUEST_UPDATE)
end
function LxQuestHandler:OnQuestLivenessRewardResp(pb)
    ModuleCenter.Quest.isActiveRwd = pb.livenessReward
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.DailyTask, pb.rewardInfo)
    -- FireEvent(EventNames.DAILY_TASK_ACTIVE_RWD)
end

function LxQuestHandler:OnQuestReceiveResp(pb)
    if pb.thingsInfo then
        ---@type LxThingsInfo 获得的奖励
        -- local thingsInfo = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.DailyTask, pb.thingsInfo)
    end
    if pb.addList and #pb.addList > 0 then
        for i,v in ipairs(pb.addList) do
            ModuleCenter.Quest:AddQuest(v)
        end
    end
    if pb.removeList and #pb.removeList > 0 then
        self:RemoveQuestList(pb.removeList)
    end
    FireEvent(EventNames.QUEST_UPDATE)
end

function LxQuestHandler:OnQuestUpdateResp(pb)
    -- if pb.addList and #pb.addList > 0 then
    --     for i,v in ipairs(pb.addList) do
    --         ModuleCenter.Quest:AddQuest(v)
    --     end
    -- end
    if pb.updateList and #pb.updateList > 0 then
        local upList = {}
        for i,v in ipairs(pb.updateList) do
            ModuleCenter.Quest:AddQuest(v)
            table.insert(upList, v.refId)
        end
    end
    if pb.removeList and #pb.removeList > 0 then
        self:RemoveQuestList(pb.removeList)
    end
    FireEvent(EventNames.QUEST_UPDATE)
end

function LxQuestHandler:RemoveQuestList(removeQuestList)
    if not removeQuestList or #removeQuestList < 1 then return end
    for i,v in ipairs(removeQuestList) do
        -- if CtrlCenter.Quest:CheckQuestIsMainType(v) then
        --     --- 主线任务，任务状态修改为已领取，重登服务端会下发
        --     ModuleCenter.Quest:ChangeQuestState(v,2)
        -- else
        --     ModuleCenter.Quest:RemoveQuest(v)
        -- end
        ModuleCenter.Quest:RemoveQuest(v)
    end
end


