function LxQuestHandler:OnQuestPlotRewardResp(pb)
    ModuleCenter.Quest:AddChapterId(pb.chapter)
    local chapterRef = GameTable.QuestStoryRef[pb.chapter]
    if chapterRef.next ~= -1 then
        ClosePanel(UiNames.MainTask)
    else
        local uiCtrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.MainTask)
        if uiCtrl then
            uiCtrl:InitTaskTypeList()
        end
    end
    local func = function()
        if chapterRef.next ~= -1 then
            local t1,t2 = CtrlCenter.Story:CheckTrigger(NewbieTriggerType.EndTask,pb.chapter)
            if(t1 > 0 and t2 > 0)then
                CtrlCenter.Story:StartStory(t2);
                return
            end
            ShowPanel(UiNames.ChapterSwitching)
        end
    end
    if pb.rewardInfo then
        ---@type LxThingsInfo 获得的奖励
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.ChapterReward, pb.rewardInfo,{
            callBack = func,
        })
    end
    
    FireEvent(EventNames.PLOT_TASK_REWARD,pb.chapter)

end
--- @param refId number 限时民心表refId
function LxQuestHandler:QuestPeopleTimeRewardReq(refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.QuestPeopleTimeRewardReq)
    proto.refId = refId
    SendMessage(LxProtoIds.QuestPeopleTimeRewardReq, proto)
end
function LxQuestHandler:OnQuestPeopleTimeRewardResp(pb)
    ModuleCenter.Quest:SetPeopleTimes(pb.refId)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Common, pb.rewardInfo,"PeopleTime")
    FireEvent(EventNames.QUEST_UPDATE)
end

function LxQuestHandler:QuestTimeLimitRewardReq(refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.QuestTimeLimitRewardReq)
    proto.refId = refId
    SendMessage(LxProtoIds.QuestTimeLimitRewardReq,proto)
end

function LxQuestHandler:OnQuestTimeLimitRewardResp(pb)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.TimeLimited, pb.rewardInfo)
    for i,v in ipairs(pb.timeLimits) do
        ModuleCenter.Quest:AddTimeLimitTask(v)
    end
    FireEvent(EventNames.TIMELIMIT_TASK_REWARD)
    FireEvent(EventNames.QUEST_UPDATE)
end

return LxQuestHandler